    32|import { ulid } from "ulid";
    33|import { createLogger } from "../observability/logger.js";
    34|import type { ChainType } from "../identity/chain.js";
    35|const logger = createLogger("registry.erc8004");
    36|
    37|/**
    38| * Guard: throws if the automaton is using a Solana wallet.
    39| * ERC-8004 is an EVM standard and requires an EVM wallet.
    40| */
    41|export function requireEvmChain(chainType?: ChainType): void {
    42|  if (chainType === "solana") {
    43|    throw new Error(
    44|      "ERC-8004 requires an EVM wallet. Solana automatons cannot register on-chain via ERC-8004. " +
    45|      "Your identity is registered via Conway API instead.",
    46|    );
    47|  }
    48|}
    49|
    50|// ─── Contract Addresses ──────────────────────────────────────
    51|
    52|const CONTRACTS = {
    53|  mainnet: {
    54|    identity: "0x8004A169FB4a3325136EB29fA0ceB6D2e539a432" as Address,
    55|    reputation: "0x8004BAa17C55a88189AE136b182e5fdA19dE9b63" as Address,
    56|    chain: base,
    57|  },
    58|  testnet: {
    59|    identity: "0x8004A169FB4a3325136EB29fA0ceB6D2e539a432" as Address,
    60|    reputation: "0x8004BAa17C55a88189AE136b182e5fdA19dE9b63" as Address,
    61|    chain: baseSepolia,
    62|  },
    63|} as const;
    64|
    65|// ─── ABI (minimal subset needed for registration) ────────────
    66|
    67|// ERC-8004 Identity Registry ABI
    68|// 正确的函数签名 (通过字节码分析确认):
    69|// - 读取: tokenURI(uint256) - 标准 ERC-721
    70|// - 更新: setAgentURI(uint256,string) - ERC-8004 自定义
    71|const IDENTITY_ABI = parseAbi([
    72|  "function register(string agentURI) external returns (uint256 agentId)",
    73|  "function setAgentURI(uint256 agentId, string newAgentURI) external",
    74|  "function tokenURI(uint256 tokenId) external view returns (string)",
    75|  "function ownerOf(uint256 tokenId) external view returns (address)",
    76|  "function totalSupply() external view returns (uint256)",
    77|  "function balanceOf(address owner) external view returns (uint256)",
    78|]);
    79|
    80|const REPUTATION_ABI = parseAbi([
    81|  "function leaveFeedback(uint256 agentId, uint8 score, string comment) external",
    82|  "function getFeedback(uint256 agentId) external view returns ((address, uint8, string, uint256)[])",
    83|]);
    84|
    85|// Phase 3.2: ERC-721 Transfer event topic signature for agent ID extraction
    86|const TRANSFER_EVENT_TOPIC = keccak256(
    87|  toBytes("Transfer(address,address,uint256)"),
    88|);
    89|
    90|type Network = "mainnet" | "testnet";
    91|
    92|/**
    93| * Resolve the RPC transport URL.
    94| * Priority: explicit parameter > AUTOMATON_RPC_URL env var > viem default (public RPC).
    95| */
    96|function resolveRpcUrl(rpcUrl?: string): string | undefined {
    97|  return rpcUrl || process.env.AUTOMATON_RPC_URL || undefined;
    98|}
    99|
   100|// ─── Preflight Check ────────────────────────────────────────────
   101|
   102|/**
   103| * Phase 3.2: Gas estimation + balance check before on-chain transaction.
   104| * Throws descriptive error if insufficient balance.
   105| */
   106|async function preflight(
   107|  account: PrivateKeyAccount,
   108|  network: Network,
   109|  functionData: {
   110|    address: Address;
   111|    abi: any;
   112|    functionName: string;
   113|    args: any[];
   114|  },
   115|  rpcUrl?: string,
   116|): Promise<void> {
   117|  const contracts = CONTRACTS[network];
   118|  const chain = contracts.chain;
   119|
   120|  const publicClient = createPublicClient({
   121|    chain,
   122|    transport: http(resolveRpcUrl(rpcUrl)),
   123|  });
   124|
   125|  // Encode calldata for accurate gas estimation
   126|  const data = encodeFunctionData({
   127|    abi: functionData.abi,
   128|    functionName: functionData.functionName,
   129|    args: functionData.args,
   130|  });
   131|
   132|  // Estimate gas
   133|  const gasEstimate = await publicClient
   134|    .estimateGas({
   135|      account: account.address,
   136|      to: functionData.address,
   137|      data,
   138|    })
   139|    .catch(() => BigInt(200_000)); // Fallback estimate
   140|
   141|  // Get gas price
   142|  const gasPrice = await publicClient
   143|    .getGasPrice()
   144|    .catch(() => BigInt(1_000_000_000)); // 1 gwei fallback
   145|
   146|  // Get balance
   147|  const balance = await publicClient.getBalance({
   148|    address: account.address,
   149|  });
   150|
   151|  const estimatedCost = gasEstimate * gasPrice;
   152|
   153|  if (balance < estimatedCost) {
   154|    throw new Error(
   155|      `Insufficient ETH for gas. Balance: ${balance} wei, estimated cost: ${estimatedCost} wei (gas: ${gasEstimate}, price: ${gasPrice} wei)`,
   156|    );
   157|  }
   158|}
   159|
   160|// ─── Transaction Logging ────────────────────────────────────────
   161|
   162|/**
   163| * Phase 3.2: Log a transaction to the onchain_transactions table.
   164| */
   165|function logTransaction(
   166|  rawDb: import("better-sqlite3").Database | undefined,
   167|  txHash: string,
   168|  chain: string,
   169|  operation: string,
   170|  status: "pending" | "confirmed" | "failed",
   171|  gasUsed?: number,
   172|  metadata?: Record<string, unknown>,
   173|): void {
   174|  if (!rawDb) return;
   175|  try {
   176|    rawDb
   177|      .prepare(
   178|        `INSERT INTO onchain_transactions (id, tx_hash, chain, operation, status, gas_used, metadata)
   179|       VALUES (?, ?, ?, ?, ?, ?, ?)`,
   180|      )
   181|      .run(
   182|        ulid(),
   183|        txHash,
   184|        chain,
   185|        operation,
   186|        status,
   187|        gasUsed ?? null,
   188|        JSON.stringify(metadata ?? {}),
   189|      );
   190|  } catch (error) {
   191|    logger.error(
   192|      "Transaction log failed:",
   193|      error instanceof Error ? error : undefined,
   194|    );
   195|  }
   196|}
   197|
   198|function updateTransactionStatus(
   199|  rawDb: import("better-sqlite3").Database | undefined,
   200|  txHash: string,
   201|  status: "pending" | "confirmed" | "failed",
   202|  gasUsed?: number,
   203|): void {
   204|  if (!rawDb) return;
   205|  try {
   206|    rawDb
   207|      .prepare(
   208|        "UPDATE onchain_transactions SET status = ?, gas_used = COALESCE(?, gas_used) WHERE tx_hash = ?",
   209|      )
   210|      .run(status, gasUsed ?? null, txHash);
   211|  } catch (error) {
   212|    logger.error(
   213|      "Transaction status update failed:",
   214|      error instanceof Error ? error : undefined,
   215|    );
   216|  }
