   219|// ─── Registration ───────────────────────────────────────────────
   220|
   221|/**
   222| * Register the automaton on-chain with ERC-8004.
   223| * Returns the agent ID (NFT token ID).
   224| *
   225| * Phase 3.2: Preflight check + transaction logging.
   226| */
   227|export async function registerAgent(
   228|  account: PrivateKeyAccount,
   229|  agentURI: string,
   230|  network: Network = "mainnet",
   231|  db: AutomatonDatabase,
   232|  rpcUrl?: string,
   233|): Promise<RegistryEntry> {
   234|  const contracts = CONTRACTS[network];
   235|  const chain = contracts.chain;
   236|  const rpc = resolveRpcUrl(rpcUrl);
   237|
   238|  // Phase 3.2: Preflight gas check
   239|  await preflight(account, network, {
   240|    address: contracts.identity,
   241|    abi: IDENTITY_ABI,
   242|    functionName: "register",
   243|    args: [agentURI],
   244|  }, rpcUrl);
   245|
   246|  const publicClient = createPublicClient({
