   248|    transport: http(rpc),
   249|  });
   250|
   251|  const walletClient = createWalletClient({
   252|    account,
   253|    chain,
   254|    transport: http(rpc),
   255|  });
   256|
   257|  // Call register(agentURI)
   258|  const hash = await walletClient.writeContract({
   259|    address: contracts.identity,
   260|    abi: IDENTITY_ABI,
   261|    functionName: "register",
   262|    args: [agentURI],
   263|  });
   264|
   265|  // Phase 3.2: Log pending transaction
   266|  logTransaction(
   267|    db.raw,
   268|    hash,
   269|    `eip155:${chain.id}`,
   270|    "register",
   271|    "pending",
   272|    undefined,
   273|    { agentURI },
   274|  );
   275|
   276|  // Wait for transaction receipt
   277|  const receipt = await publicClient.waitForTransactionReceipt({ hash });
   278|
   279|  // Phase 3.2: Update transaction status
   280|  const gasUsed = receipt.gasUsed ? Number(receipt.gasUsed) : undefined;
   281|  updateTransactionStatus(
   282|    db.raw,
   283|    hash,
   284|    receipt.status === "success" ? "confirmed" : "failed",
   285|    gasUsed,
   286|  );
   287|
   288|  // Phase 3.2: Extract agentId using Transfer event topic signature
   289|  let agentId = "0";
