   291|    if (log.topics.length >= 4 && log.topics[0] === TRANSFER_EVENT_TOPIC) {
   292|      // Transfer(address from, address to, uint256 tokenId)
   293|      agentId = BigInt(log.topics[3]!).toString();
   294|      break;
   295|    }
   296|  }
   297|
   298|  const entry: RegistryEntry = {
   299|    agentId,
   300|    agentURI,
   301|    chain: `eip155:${chain.id}`,
   302|    contractAddress: contracts.identity,
   303|    txHash: hash,
   304|    registeredAt: new Date().toISOString(),
   305|  };
   306|
   307|  db.setRegistryEntry(entry);
   308|  return entry;
