    16|import { getSurvivalTier, formatCredits } from "../conway/credits.js";
    17|import { getUsdcBalance } from "../conway/x402.js";
    18|
    19|export interface ResourceStatus {
    20|  financial: FinancialState;
    21|  tier: SurvivalTier;
    22|  previousTier: SurvivalTier | null;
    23|  tierChanged: boolean;
    24|  sandboxHealthy: boolean;
    25|}
    26|
    27|/**
    28| * Check all resources and return current status.
    29| */
    30|export async function checkResources(
    31|  identity: AutomatonIdentity,
    32|  conway: ConwayClient,
    33|  db: AutomatonDatabase,
    34|): Promise<ResourceStatus> {
    35|  // Check credits
    36|  let creditsCents = 0;
    37|  try {
    38|    creditsCents = await conway.getCreditsBalance();
    39|  } catch {}
    40|
    41|  // Check USDC
    42|  let usdcBalance = 0;
    43|  try {
    44|    usdcBalance = await getUsdcBalance(identity.address);
    45|  } catch {}
    46|
    47|  // Check sandbox health
    48|  let sandboxHealthy = true;
    49|  try {
    50|    const result = await conway.exec("echo ok", 5000);
    51|    sandboxHealthy = result.exitCode === 0;
    52|  } catch {
    53|    sandboxHealthy = false;
    54|  }
    55|
    56|  const financial: FinancialState = {
    57|    creditsCents,
    58|    usdcBalance,
    59|    lastChecked: new Date().toISOString(),
    60|  };
    61|
    62|  const tier = getSurvivalTier(creditsCents);
    63|  const prevTierStr = db.getKV("current_tier");
    64|  const previousTier = (prevTierStr as SurvivalTier) || null;
    65|  const tierChanged = previousTier !== null && previousTier !== tier;
    66|
    67|  // Store current tier
    68|  db.setKV("current_tier", tier);
    69|
    70|  // Store financial state
    71|  db.setKV("financial_state", JSON.stringify(financial));
    72|
    73|  return {
    74|    financial,
    75|    tier,
    76|    previousTier,
    77|    tierChanged,
    78|    sandboxHealthy,
    79|  };
    80|}
